// OPTIMIZED: Parse incoming device messages with ultra-minimal heartbeat + ultra-compact sensor support
// Supports: heartbeat ('h'), compact sensors (S57.41, I1.2,3.4,5.6), JSON

const payload = msg.payload;
msg.sessionId = msg._session;

// FAST PATH 1: Ultra-minimal heartbeat (single character 'h')
if (payload === 'h') {
    msg.messageType = 'heartbeat';
    msg.parsedMessage = null;
    msg.deviceUUID = null;
    return msg;
}

// FAST PATH 2: Ultra-compact sensor data (starts with uppercase letter)
// Formats: S57.41, B1, I0.12,-0.05,9.81,...
if (payload.length >= 2 && payload[0] >= 'A' && payload[0] <= 'Z' && payload[1] !== '{') {
    const code = payload[0];
    const valueStr = payload.substring(1);

    // Parse based on sensor code
    msg.messageType = 'sensor_data_compact';
    msg.sensorCode = code;
    msg.sensorValueStr = valueStr;
    msg.deviceUUID = null;  // Will be resolved by session lookup
    return msg;
}

// Standard path: JSON messages
let message;
try {
    message = JSON.parse(payload);
    msg.parsedMessage = message;

    // Determine message type
    if (message.type === 'device_registration') {
        msg.messageType = 'device_registration';
        msg.deviceUUID = message.device;
    } else if (message.s) {
        // Simplified sensor data format: {"s": "sensor", "v": value}
        msg.messageType = 'sensor_data';
        msg.deviceUUID = null; // Will be resolved by session lookup
    } else {
        msg.messageType = 'unknown';
        msg.deviceUUID = message.device || 'unknown';
    }

    return msg;

} catch (e) {
    node.error('Failed to parse device message: ' + e.message, msg);
    return null;
}

// OPTIMIZED: Handle device registration with fast-path for known devices
// Known devices only update socketID, new devices get full registration
// ENHANCED: Build actuator AND sensor code mapping for ultra-compact commands
// ENHANCED: Added verification logging to diagnose storage issues

const regMsg = msg.parsedMessage;
const deviceUUID = msg.deviceUUID;
const sessionId = msg.sessionId;

node.log(`\n=== REGISTRATION STARTED ===`);
node.log(`Device UUID: ${deviceUUID}`);
node.log(`Device name: ${regMsg.device_name}`);
node.log(`Session ID: ${JSON.stringify(sessionId)}`);

// Validate registration message
if (!deviceUUID || !regMsg.device_name) {
    node.error('Invalid registration message: missing device UUID or name', msg);
    return null;
}

// Actuator type to code mapping (standardized codes)
const actuatorTypeToCode = {
    'led': 'L',
    'pwm_led': 'P',
    'servo': 'S',
    'dc_motor': 'M',
    'rgb_led': 'R',
    'buzzer': 'B',
    'relay': 'E',  // E for rElay (L taken by led)
    'stepper': 'T',  // T for sTep
    'fan': 'F',
    'valve': 'V',
    'heater': 'H',
    'tone_buzzer': 'Z',  // Z for buzZer tone
    'pwm': 'W',  // W for pWm
    'dac': 'D',
    'mp3_player': 'X'  // X for MP3 (complex JSON)
};

// Sensor type to code mapping (standardized codes)
const sensorTypeToCode = {
    'analog': 'A',
    'slider': 'S',
    'potentiometer': 'S',
    'temperature': 'T',
    'humidity': 'H',
    'light': 'L',
    'lux': 'L',
    'pressure': 'P',
    'distance': 'D',
    'ultrasonic': 'D',
    'button': 'B',
    'digital': 'B',
    'motion': 'M',
    'pir': 'M',
    'imu': 'I',
    'imu_6dof': 'I',
    'imu_9dof': 'I',
    'imu_10dof': 'I',
    'quaternion': 'Q',
    'sound': 'N',  // N for Noise
    'gas': 'G',
    'voltage': 'V',
    'current': 'C',
    'mp3_status': 'X'  // X for MP3 status (complex JSON)
};

// Get devices from flow context
const devices = flow.get('devices') || {};
const existingDevice = devices[deviceUUID];

if (existingDevice) {
    // FAST PATH: Known device reconnecting - update socket AND peripherals
    // IMPORTANT: Always refresh peripheral config to support prototyping workflows
    // where sensors/actuators may be changed between connections
    node.log(`✅ Known device reconnecting: ${regMsg.device_name} (${deviceUUID.substring(0,8)}...)`);

    const sensorCount = (regMsg.sensors || []).length;
    const actuatorCount = (regMsg.actuators || []).length;
    node.log(`   Refreshing config: ${sensorCount} sensors, ${actuatorCount} actuators`);

    // Build actuator code map for this device
    const actuatorCodeMap = {};
    (regMsg.actuators || []).forEach(actuator => {
        const code = actuatorTypeToCode[actuator.type];
        if (code) {
            actuatorCodeMap[actuator.name] = {
                code: code,
                type: actuator.type,
                dataType: actuator.data_type
            };
            node.log(`   Actuator: ${actuator.name} → ${code} (${actuator.type})`);
        }
    });

    // Build sensor code map for this device
    const sensorCodeMap = {};
    (regMsg.sensors || []).forEach(sensor => {
        const code = sensorTypeToCode[sensor.type];
        if (code) {
            sensorCodeMap[sensor.name] = {
                code: code,
                type: sensor.type,
                dataType: sensor.data_type
            };
            node.log(`   Sensor: ${sensor.name} → ${code} (${sensor.type})`);
        }
    });

    // Update ALL device properties including peripherals
    existingDevice.sessionId = sessionId;
    existingDevice.deviceName = regMsg.device_name;
    existingDevice.deviceType = regMsg.device_type || 'ESP32';
    existingDevice.library = regMsg.library;
    existingDevice.version = regMsg.version;
    existingDevice.ip = regMsg.ip;
    existingDevice.sensors = regMsg.sensors || [];
    existingDevice.actuators = regMsg.actuators || [];
    existingDevice.actuatorCodeMap = actuatorCodeMap;
    existingDevice.sensorCodeMap = sensorCodeMap;
    existingDevice.status = 'acknowledged';
    existingDevice.lastHeartbeat = Date.now();
    existingDevice.lastSeen = new Date().toISOString();

    // Save updated device
    flow.set('devices', devices);

    node.status({
        fill: 'green',
        shape: 'ring',
        text: `Reconnected: ${regMsg.device_name}`
    });
} else {
    // NEW DEVICE: Full registration process
    node.log(`🆕 New device registering: ${regMsg.device_name} (${deviceUUID.substring(0,8)}...)`);

    const sensorCount = (regMsg.sensors || []).length;
    const actuatorCount = (regMsg.actuators || []).length;
    node.log(`   ${sensorCount} sensors, ${actuatorCount} actuators`);

    // Build actuator code map for this device
    const actuatorCodeMap = {};
    (regMsg.actuators || []).forEach(actuator => {
        const code = actuatorTypeToCode[actuator.type];
        if (code) {
            actuatorCodeMap[actuator.name] = {
                code: code,
                type: actuator.type,
                dataType: actuator.data_type
            };
            node.log(`   Actuator: ${actuator.name} → ${code} (${actuator.type})`);
        }
    });

    // Build sensor code map for this device
    const sensorCodeMap = {};
    (regMsg.sensors || []).forEach(sensor => {
        const code = sensorTypeToCode[sensor.type];
        if (code) {
            sensorCodeMap[sensor.name] = {
                code: code,
                type: sensor.type,
                dataType: sensor.data_type
            };
            node.log(`   Sensor: ${sensor.name} → ${code} (${sensor.type})`);
        }
    });

    devices[deviceUUID] = {
        sessionId: sessionId,
        deviceName: regMsg.device_name,
        deviceType: regMsg.device_type || 'ESP32',
        library: regMsg.library,
        version: regMsg.version,
        ip: regMsg.ip,
        sensors: regMsg.sensors || [],
        actuators: regMsg.actuators || [],
        actuatorCodeMap: actuatorCodeMap,  // Store actuator code mapping
        sensorCodeMap: sensorCodeMap,  // Store sensor code mapping
        status: 'acknowledged',
        lastHeartbeat: Date.now(),
        registrationTime: new Date().toISOString(),
        lastSeen: new Date().toISOString()
    };

    flow.set('devices', devices);

    node.status({
        fill: 'green',
        shape: 'dot',
        text: `New: ${regMsg.device_name}`
    });
}

// VERIFICATION: Check device was stored correctly
const storedDevices = flow.get('devices') || {};
const verifyDevice = storedDevices[deviceUUID];
node.log(`\n=== STORAGE VERIFICATION ===`);
node.log(`Total devices in flow context: ${Object.keys(storedDevices).length}`);
if (verifyDevice) {
    node.log(`✅ Device ${deviceUUID.substring(0,8)} VERIFIED in storage`);
    node.log(`   Name: ${verifyDevice.deviceName}`);
    node.log(`   Session: ${JSON.stringify(verifyDevice.sessionId)}`);
    node.log(`   SensorCodeMap keys: ${Object.keys(verifyDevice.sensorCodeMap || {}).join(', ') || 'none'}`);
} else {
    node.error(`❌ CRITICAL: Device ${deviceUUID.substring(0,8)} NOT FOUND in storage after flow.set()!`);
    node.error(`   This indicates a flow context storage failure`);
}

// Generate registration acknowledgment (same for both paths)
const ackResponse = {
    type: 'registration_ack',
    device: deviceUUID,
    status: 'accepted',
    message: existingDevice ? 'Device reconnected' : 'Device registered successfully',
    timestamp: Date.now()
};

// Prepare response message
msg.payload = JSON.stringify(ackResponse);
msg._session = sessionId;
msg.ackResponse = ackResponse;

node.log(`=== REGISTRATION COMPLETE - Sending ACK ===\n`);

// Build webhook message to forward registration to backend
const webhookMsg = {
    payload: {
        uuid: deviceUUID,
        name: regMsg.device_name,
        type: regMsg.device_type || 'ESP32',
        sensors: regMsg.sensors || [],
        actuators: regMsg.actuators || []
    },
    headers: { 'Content-Type': 'application/json' }
};

return [msg, webhookMsg];

// OPTIMIZED: Ultra-minimal heartbeat handler using session-based device lookup
// Heartbeat is now just 'h' - device identified by WebSocket session

const sessionId = msg.sessionId;
const devices = flow.get('devices') || {};

// Lookup device by session ID (similar to sensor data handler)
let deviceUUID = null;
let device = null;

for (const uuid in devices) {
    const candidate = devices[uuid];
    if (candidate.sessionId) {
        const storedSession = candidate.sessionId;

        // STRICT: Only JSON comparison - no loose String() matching
        if (JSON.stringify(storedSession) === JSON.stringify(sessionId)) {
            deviceUUID = uuid;
            device = candidate;
            break;
        }
    }
}

// Device not found - request re-registration
if (!device) {
    node.warn(`[HEARTBEAT] ❌ Unknown session - requesting re-registration`);

    const reRegRequest = {
        type: 're_register_request',
        message: 'Session not found after server restart, please re-register',
        timestamp: Date.now(),
        reason: 'heartbeat_session_not_found'
    };

    msg.payload = JSON.stringify(reRegRequest);
    msg._session = sessionId;
    return msg;
}

// SUCCESS: Update heartbeat timestamp (minimal overhead)
device.lastHeartbeat = Date.now();
device.status = 'acknowledged';
flow.set('devices', devices);

// No output for successful heartbeat (silent operation)
return null;

// Handle simplified sensor data and lookup device by session
// FIXED: Strict session matching to prevent cross-device data leakage

const sensorMsg = msg.parsedMessage;
const sessionId = msg.sessionId;

// Get devices from flow context
const devices = flow.get('devices') || {};
let deviceUUID = null;
let device = null;

// Create a unique session key for comparison
// This handles both object and string session IDs
const getSessionKey = (session) => {
    if (!session) return null;
    if (typeof session === 'string') return session;
    if (session.id) return session.id;
    // For objects, use JSON but ensure consistent key ordering
    return JSON.stringify(session);
};

const incomingKey = getSessionKey(sessionId);

// DEBUG: Log incoming session
node.log(`[SENSOR] Incoming session key: ${incomingKey}`);
node.log(`[SENSOR] Checking ${Object.keys(devices).length} registered devices`);

// STRICT session matching - only JSON comparison, no loose String() matching
for (const uuid in devices) {
    const candidateDevice = devices[uuid];
    if (candidateDevice.sessionId) {
        const storedKey = getSessionKey(candidateDevice.sessionId);

        node.log(`[SENSOR] Device ${candidateDevice.deviceName} (${uuid.substring(0,8)}): stored key = ${storedKey}`);

        if (incomingKey && storedKey && incomingKey === storedKey) {
            deviceUUID = uuid;
            device = candidateDevice;
            node.log(`[SENSOR] ✓ MATCHED: ${device.deviceName} → UUID ${uuid}`);
            break;
        } else {
            node.log(`[SENSOR] ✗ No match`);
        }
    }
}

// Handle unknown session
if (!deviceUUID || !device) {
    node.warn(`[SENSOR] ❌ Unknown session - requesting re-registration`);

    node.status({fill: 'yellow', shape: 'ring', text: 'Unknown session'});

    const reRegRequest = {
        type: 're_register_request',
        message: 'Session not found, please re-register',
        timestamp: Date.now(),
        reason: 'session_lookup_failed'
    };

    msg.payload = JSON.stringify(reRegRequest);
    msg._session = sessionId;
    msg.isReRegRequest = true;

    return msg;
}

// SUCCESS: Device found
node.log(`[SENSOR] ✅ ${device.deviceName} (${deviceUUID.substring(0,8)}): ${sensorMsg.s} = ${sensorMsg.v}`);

device.lastSeen = new Date().toISOString();
device.lastHeartbeat = Date.now();
flow.set('devices', devices);

const sensorData = {
    d: deviceUUID.substring(0, 8),
    s: sensorMsg.s,
    v: sensorMsg.v,
    t: Date.now()
};

node.status({
    fill: 'blue',
    shape: 'dot',
    text: `${device.deviceName}: ${sensorMsg.s} = ${sensorMsg.v}`
});

msg.payload = sensorData;
msg.isPWABroadcast = true;
msg.deviceUUID = deviceUUID;

return msg;

// Inspect flow context for debugging
const devices = flow.get('devices') || {};
const deviceCount = Object.keys(devices).length;

node.log(`=== FLOW CONTEXT INSPECTION ===`);
node.log(`Device count: ${deviceCount}`);

for (const uuid in devices) {
    const device = devices[uuid];
    node.log(`Device: ${device.deviceName || 'unnamed'} (${uuid.substring(0,8)}...)`);
    node.log(`  Session: ${JSON.stringify(device.sessionId)}`);
    node.log(`  Status: ${device.status}`);
    node.log(`  Last seen: ${device.lastSeen}`);
    node.log(`  Sensors: ${(device.sensors || []).length}`);
    node.log(`  Actuators: ${(device.actuators || []).length}`);
}

node.status({
    fill: deviceCount > 0 ? 'green' : 'red',
    shape: 'dot',
    text: `${deviceCount} devices in context`
});

msg.payload = {
    deviceCount,
    devices: Object.keys(devices).map(uuid => ({
        uuid: uuid.substring(0,8),
        name: devices[uuid].deviceName,
        status: devices[uuid].status,
        sessionId: devices[uuid].sessionId,
        lastSeen: devices[uuid].lastSeen
    }))
};

return msg;

// Handle NodeRED startup - prepare for device reconnections
// CRITICAL: After restart, flow context is empty but devices may still be connected

node.log(`=== NODERED STARTUP HANDLER ===`);
node.log(`Initializing flow context and preparing for device reconnections`);

// Initialize empty devices context if not exists
const devices = flow.get('devices') || {};
const deviceCount = Object.keys(devices).length;

node.log(`Current devices in context: ${deviceCount}`);

if (deviceCount === 0) {
    node.log(`⚠️  Flow context is empty - this is normal after restart`);
    node.log(`⚠️  Any connected ESP32 devices will need to re-register`);
    node.log(`⚠️  Re-registration requests will be sent when simplified sensor data is received`);

    flow.set('devices', {});
    flow.set('startup_time', Date.now());

    node.status({fill: 'yellow', shape: 'ring', text: 'Awaiting device registrations'});
} else {
    node.log(`✅ Found ${deviceCount} devices in context - normal operation`);
    node.status({fill: 'green', shape: 'dot', text: `${deviceCount} devices restored`});
}

// Set a flag that we've just started up (useful for first-time device connections)
flow.set('recently_started', true);

// Clear the recently_started flag after 30 seconds
setTimeout(() => {
    flow.set('recently_started', false);
    node.log(`Startup period ended - normal operation mode`);
}, 30000);

return null;

// Monitor device health and REMOVE stale connections
// Devices that miss heartbeats for too long are removed from registry
// Note: WebSocket node count is TCP-level and will timeout separately

const devices = flow.get('devices') || {};
const now = Date.now();
const staleThreshold = 15000;  // 15 seconds (about 4 missed heartbeats)
const removeThreshold = 60000; // 60 seconds - remove from registry

let healthyDevices = 0;
let staleDevices = 0;
let removedDevices = [];
let recentDevices = [];

for (const uuid in devices) {
    const device = devices[uuid];
    const lastHeartbeat = device.lastHeartbeat || 0;
    const timeSinceLastSeen = now - lastHeartbeat;

    if (timeSinceLastSeen > removeThreshold) {
        // REMOVE: Device hasn't been seen for too long
        removedDevices.push(device.deviceName);
        delete devices[uuid];
        node.log(`🗑️ Removed stale device: ${device.deviceName} (${Math.round(timeSinceLastSeen/1000)}s)`);
    } else if (timeSinceLastSeen > staleThreshold) {
        staleDevices++;
        device.status = 'stale';
        node.log(`📵 Device ${device.deviceName} is stale (${Math.round(timeSinceLastSeen/1000)}s)`);
    } else {
        healthyDevices++;
        device.status = 'acknowledged';
        if (timeSinceLastSeen < 5000) {
            recentDevices.push(device.deviceName);
        }
    }
}

// Update device registry
flow.set('devices', devices);

// Status display
let statusText = `${healthyDevices} active`;
if (staleDevices > 0) {
    statusText += `, ${staleDevices} stale`;
}
if (removedDevices.length > 0) {
    statusText += ` (removed ${removedDevices.length})`;
}

node.status({
    fill: staleDevices > 0 ? 'yellow' : (healthyDevices > 0 ? 'green' : 'gray'),
    shape: 'dot',
    text: statusText
});

// Log health summary every minute
const lastLogTime = context.get('last_health_log') || 0;
if (now - lastLogTime > 60000) {
    node.log(`=== DEVICE HEALTH: ${healthyDevices} active, ${staleDevices} stale ===`);
    context.set('last_health_log', now);
}

return null;

// OPTIMIZED: Fast PWA message parsing with minimal overhead
// ENHANCED: Added pwa_ping for live session tracking (immediate disconnect detection)

let message;
try {
    message = JSON.parse(msg.payload);
    msg.parsedMessage = message;
    msg.sessionId = msg._session;

    // Fast message type detection
    const msgType = message.type;

    // FAST PATH 1: PWA ping (for live session tracking)
    if (msgType === 'pwa_ping') {
        msg.messageType = 'pwa_ping';
        msg.clientId = message.client_id || 'unknown';
        return msg;
    }

    // FAST PATH 2: Actuator commands (skip logging/status)
    // Accept both 'actuator_cmd' and 'actuator_command' for compatibility
    if (msgType === 'actuator_cmd' || msgType === 'actuator_command') {
        msg.messageType = 'actuator_cmd';
        msg.deviceUUID = message.device;
        msg.clientId = message.client_id || 'unknown';
        return msg;
    }

    // Standard path for other message types
    if (msgType === 'pwa_registration') {
        msg.messageType = 'pwa_registration';
        msg.clientId = message.client_id;
    } else if (msgType === 'get_devices') {
        msg.messageType = 'get_devices';
        msg.clientId = message.client_id || 'unknown';
    } else if (msgType === 'get_pwa_clients') {
        msg.messageType = 'get_pwa_clients';
        msg.clientId = message.client_id || 'unknown';
    } else if (msgType === 'subscribe') {
        msg.messageType = 'subscribe';
        msg.deviceUUID = message.device;
        msg.clientId = message.client || 'unknown';
    } else if (msgType === 'unsubscribe') {
        msg.messageType = 'unsubscribe';
        msg.deviceUUID = message.device;
        msg.clientId = message.client || 'unknown';
    } else {
        msg.messageType = 'unknown';
        msg.clientId = message.client_id || 'unknown';
    }

    return msg;

} catch (e) {
    return null;
}

// Handle PWA unsubscription from devices
// Removes device from client's subscription list

const clientId = msg.clientId;
const deviceUUID = msg.deviceUUID;
const sessionId = msg.sessionId;

node.log(`[UNSUBSCRIBE] Client ${clientId} unsubscribing from ${deviceUUID}`);

if (!clientId || !deviceUUID) {
    node.error('[UNSUBSCRIBE] Invalid: missing client ID or device UUID');
    return null;
}

// Get PWA clients from flow context
const pwaClients = flow.get('pwa_clients') || {};
const client = pwaClients[clientId];

if (!client) {
    node.warn(`[UNSUBSCRIBE] Client ${clientId} not found`);
    return null;
}

// Remove device from subscriptions
if (client.subscriptions) {
    const index = client.subscriptions.indexOf(deviceUUID);
    if (index > -1) {
        client.subscriptions.splice(index, 1);
        node.log(`[UNSUBSCRIBE] Removed ${deviceUUID.substring(0,8)}... from ${client.clientName}`);
    }
}

// Save updated client
client.lastSeen = new Date().toISOString();
flow.set('pwa_clients', pwaClients);

node.status({
    fill: 'yellow',
    shape: 'ring',
    text: `${client.clientName} -x- ${deviceUUID.substring(0,8)}...`
});

// Send acknowledgment
const response = {
    type: 'unsubscription_ack',
    device: deviceUUID,
    client_id: clientId,
    status: 'accepted',
    timestamp: Date.now()
};

msg.payload = JSON.stringify(response);
msg._session = sessionId;
return msg;

// Handle PWA registration and store to flow context
// Manages PWA client registry for broadcasting and subscription management

const regMsg = msg.parsedMessage;
const clientId = msg.clientId;
const sessionId = msg.sessionId;

// Validate registration message
if (!clientId || !regMsg.client_name) {
    node.error('Invalid PWA registration message: missing client ID or name', msg);
    return null;
}

// Get PWA clients from flow context
const pwaClients = flow.get('pwa_clients') || {};

// Store PWA client registration data
pwaClients[clientId] = {
    sessionId: sessionId,
    clientName: regMsg.client_name,
    userAgent: regMsg.user_agent || 'Unknown',
    status: 'registered',
    registrationTime: new Date().toISOString(),
    lastSeen: new Date().toISOString(),
    subscriptions: [] // Devices this client is subscribed to
};

// Save back to flow context
flow.set('pwa_clients', pwaClients);

// Log registration
node.log(`PWA registered: ${regMsg.client_name} (${clientId})`);

// Update node status
node.status({
    fill: 'green',
    shape: 'dot',
    text: `Registered: ${regMsg.client_name}`
});

// Generate registration acknowledgment message
const ackResponse = {
    type: 'pwa_registration_ack',
    client_id: clientId,
    status: 'accepted',
    message: 'PWA client registered successfully',
    timestamp: Date.now()
};

// Prepare response message with session targeting
msg.payload = JSON.stringify(ackResponse);
msg._session = sessionId;  // Target specific PWA session
msg.ackResponse = ackResponse;  // For debugging

return msg;

// ULTRA-FAST: Handle PWA ping for live session tracking
// PWA clients send ping every 5s, stale after 15s = immediate disconnect detection
// This is the PRIMARY mechanism for tracking live connections

const clientId = msg.clientId;
const sessionId = msg.sessionId;

// Get PWA clients from flow context
const pwaClients = flow.get('pwa_clients') || {};

// Try to find client by client_id first
let client = pwaClients[clientId];

// If not found by ID, try to find by session (fallback for unregistered pings)
if (!client) {
    for (const id in pwaClients) {
        const candidate = pwaClients[id];
        if (candidate.sessionId) {
            const storedSession = candidate.sessionId;
            if (storedSession === sessionId ||
                JSON.stringify(storedSession) === JSON.stringify(sessionId) ||
                String(storedSession) === String(sessionId)) {
                client = candidate;
                break;
            }
        }
    }
}

if (!client) {
    // Unknown client - they need to register first
    node.warn(`Ping from unregistered PWA client: ${clientId}`);
    return null;
}

// Update lastSeen timestamp (critical for disconnect detection)
client.lastSeen = new Date().toISOString();
client.lastPing = Date.now();
flow.set('pwa_clients', pwaClients);

// Silent operation - no output, no logging for performance
return null;

// Provide list of registered devices to PWA clients
// Returns all devices with their current status and capabilities

const clientId = msg.clientId;
const sessionId = msg.sessionId;

// Get devices from flow context
const devices = flow.get('devices') || {};
const deviceList = [];

// Convert devices object to array format for PWA
for (const uuid in devices) {
    const device = devices[uuid];
    deviceList.push({
