};

// HTTP success response (reuse original msg which carries req/res from HTTP-in)
msg.payload = { sent: true, device: deviceUUID, actuator, value };
msg.statusCode = 200;

node.status({ fill: 'green', shape: 'dot', text: `${actuator} → ${device.deviceName}` });
return [cmdMsg, msg, null];

// Handle device registration via HTTP POST
// Validates body, stores device in flow context, forwards to backend webhook

const body = msg.payload;
const uuid = body.device;
const deviceName = body.device_name;

if (!uuid || !deviceName) {
    msg.payload = { error: 'device (UUID) and device_name are required' };
    msg.statusCode = 400;
    return [null, null, msg];
}

// Actuator type to code mapping (same as device_registration_handler)
const actuatorTypeToCode = {
    'led': 'L', 'pwm_led': 'P', 'servo': 'S', 'dc_motor': 'M',
    'rgb_led': 'R', 'buzzer': 'B', 'relay': 'E', 'stepper': 'T',
    'fan': 'F', 'valve': 'V', 'heater': 'H', 'tone_buzzer': 'Z',
    'pwm': 'W', 'dac': 'D', 'mp3_player': 'X'
};

// Sensor type to code mapping
const sensorTypeToCode = {
    'analog': 'A', 'slider': 'S', 'potentiometer': 'S',
    'temperature': 'T', 'humidity': 'H', 'light': 'L', 'lux': 'L',
    'pressure': 'P', 'distance': 'D', 'ultrasonic': 'D',
    'button': 'B', 'digital': 'B', 'motion': 'M', 'pir': 'M',
    'imu': 'I', 'imu_6dof': 'I', 'imu_9dof': 'I', 'imu_10dof': 'I',
    'quaternion': 'Q', 'sound': 'N', 'gas': 'G',
    'voltage': 'V', 'current': 'C', 'mp3_status': 'X'
};

// Build code maps
const actuatorCodeMap = {};
(body.actuators || []).forEach(a => {
    const code = actuatorTypeToCode[a.type];
    if (code) actuatorCodeMap[a.name] = { code, type: a.type, dataType: a.data_type };
});

const sensorCodeMap = {};
(body.sensors || []).forEach(s => {
    const code = sensorTypeToCode[s.type];
    if (code) sensorCodeMap[s.name] = { code, type: s.type, dataType: s.data_type };
});

// Store device in flow context (sessionId = 'http' indicates no WS session)
const devices = flow.get('devices') || {};
const existing = devices[uuid];

if (existing) {
    // Preserve WS sessionId if device is also connected via WS
    existing.deviceName = deviceName;
    existing.deviceType = body.device_type || 'ESP32';
    existing.sensors = body.sensors || [];
    existing.actuators = body.actuators || [];
    existing.actuatorCodeMap = actuatorCodeMap;
    existing.sensorCodeMap = sensorCodeMap;
    existing.lastSeen = new Date().toISOString();
    if (!existing.sessionId || existing.sessionId === 'http') {
        existing.sessionId = 'http';
    }
} else {
    devices[uuid] = {
        sessionId: 'http',
        deviceName: deviceName,
        deviceType: body.device_type || 'ESP32',
        sensors: body.sensors || [],
        actuators: body.actuators || [],
        actuatorCodeMap: actuatorCodeMap,
        sensorCodeMap: sensorCodeMap,
        status: 'acknowledged',
        lastHeartbeat: Date.now(),
        registrationTime: new Date().toISOString(),
        lastSeen: new Date().toISOString()
    };
}

flow.set('devices', devices);
node.log(`[HTTP REG] Device ${uuid.substring(0,8)} registered: ${deviceName}`);
node.status({ fill: 'green', shape: 'dot', text: `Registered: ${deviceName}` });

// Output 1: Webhook forward to backend
const webhookMsg = {
    payload: {
        uuid: uuid,
        name: deviceName,
        type: body.device_type || 'ESP32',
        sensors: body.sensors || [],
        actuators: body.actuators || []
    },
    headers: { 'Content-Type': 'application/json' }
};

// Output 2: Success response (reuse msg for HTTP response context)
msg.payload = {
    type: 'registration_ack',
    status: 'accepted',
    device: uuid
};
msg.statusCode = 200;

return [webhookMsg, msg, null];

// Validate HTTP data POST body and prepare verify request
const body = msg.payload;

if (!body.device || !body.readings || !Array.isArray(body.readings) || body.readings.length === 0) {
    msg.payload = { error: 'device (UUID) and readings[] are required' };
    msg.statusCode = 400;
    return [null, msg];
}

// Save original body for later processing
msg.deviceData = body;
// Set up URL for verify request (method is set on the http-request node)
msg.url = 'http://127.0.0.1:2026/api/webhook/verify-device/' + encodeURIComponent(body.device);
msg.headers = {};
msg.payload = '';

return [msg, null];

// Process verified device data — broadcast to WS subscribers + webhook
const verifyResult = msg.payload;
const deviceData = msg.deviceData;

if (!verifyResult || !verifyResult.claimed) {
    msg.payload = { error: 'Device not claimed. Register and claim it first.' };
    msg.statusCode = 403;
    return [null, null, msg];
}

const uuid = deviceData.device;

// Send each reading into the standard sensor data pipeline
for (const r of deviceData.readings) {
    const sensorMsg = {
        payload: {
            d: uuid.substring(0, 8),
            s: r.sensor,
            v: r.value,
            t: r.timestamp || Date.now()
        },
        deviceUUID: uuid,
        isPWABroadcast: true
    };
    node.send([sensorMsg, null, null]);
}

// Success response (reuse original msg for HTTP response context)
msg.payload = { stored: true, count: deviceData.readings.length };
msg.statusCode = 200;

node.status({ fill: 'green', shape: 'dot', text: `${deviceData.readings.length} readings from ${uuid.substring(0,8)}` });
return [null, msg, null];
